item.description:
#### 需求：用C++实现一个通讯录管理系统，实现以下功能:

1. 创建通讯录(包括姓名,性别,年龄,联系电话,家庭住址)

2. 显示通讯录(显示通讯录成员的基本信息)

3. 删除通讯录(删除通讯录中想删除的联系人)

4. 查找通讯录(按照联系人的名字查找到具体的联系人)

5. 修改通讯录(修改通讯录中联系人的基本信息)

6. 清空通讯录(删除通讯录中的所有联系人)

7. 退出通讯录(退出通讯录界面)



#### 考察知识点：

- struct结构体——定义、构造、初始化
- 枚举类型
- switch-case
- 数组操作
- 链表操作

#### 功能实现：

- 查询界面展示
- 增删查改



#### struct结构体

- struct结构体的定义

  - 代码如下：

    - ```c++
      struct Person {
          string name;
          Sex sex; // male or female
          int age;
          string phoneNumber;
          string address;
      
          Person() : name(''), sex(FEMALE), age(0), phoneNumber(''), address('') {};
          Person(string n, Sex s, int a, string pN, string addr) : name(n), sex(s), age(a), phoneNumber(pN), address(addr) {};
      };
      ```

    - 包含属性声明、方法声明、构造方法声明

    - struct与C++中类的区别

      - struct声明的结构体中的变量和方法的访问符都是public

  - 与C的不同

    - C在声明结构体时必须带struct，而C++中可以省略struct，这也是C中的结构体定义常使用typedef取别名的原因

  - 起别名方式

    - typedef（沿用C）

      - ```c++
        typedef struct Person {
            string name;
            Sex sex; // male or female
            int age;
            string phoneNumber;
            string address;
        
            Person() : name(''), sex(FEMALE), age(0), phoneNumber(''), address('') {};
            Person(string n, Sex s, int a, string pN, string addr) : name(n), sex(s), age(a), phoneNumber(pN), address(addr) {};
        } per;
        ```

    - 使用using（C++11及以后加入的新特性）

      - ```c++
        using per = struct Person;
        ```

- struct结构体的构造方法

  - 无参构造：`Person() : name(''), sex(FEMALE), age(0), phoneNumber(''), address('') {};`
  - 有参构造：`Person(string n, Sex s, int a, string pN, string addr) : name(n), sex(s), age(a), phoneNumber(pN), address(addr) {};`

- struct结构体的初始化

  - 直接在结构体定义的时候声明变量

    - ```c++
      struct Person {
          string name;
          Sex sex; // male or female
          int age;
          string phoneNumber;
          string address;
      
          Person() : name(''), sex(FEMALE), age(0), phoneNumber(''), address('') {};
          Person(string n, Sex s, int a, string pN, string addr) : name(n), sex(s), age(a), phoneNumber(pN), address(addr) {};
      } per;
      ```

  - 其他位置声明变量<!--(当Person结构体存在无参构造方法或Person结构体只包含基本类型时，可以直接用Person()初始化)-->

    - 兼容C: `struct Person person = struct Person()`
    - C++特性: `Person person = Person()`



#### 查询界面展示

输出提示，获取用户输入的选项，用户输入作为循环跳出条件（`swicth-case`处理各种情况）

代码如下：

```c++
	while (true) {
        cout << '********请选择功能: ********' << endl;
        // 1. 创建通讯录(包括姓名,性别,年龄,联系电话,家庭住址)
        cout << '******* 1.创建联系人 *******' << endl;
        // 2. 显示通讯录(显示通讯录成员的基本信息)
        cout << '******* 2.显示通讯录 *******' << endl;
        // 3. 删除通讯录(删除通讯录中想删除的联系人)
        cout << '******* 3.删除联系人 *******' << endl;
        // 4. 查找通讯录(按照联系人的名字查找到具体的联系人)
        cout << '******* 4.查找联系人 *******' << endl;
        // 5. 修改通讯录(修改通讯录中联系人的基本信息)
        cout << '******* 5.修改联系人 *******' << endl;
        // 6. 清空通讯录(删除通讯录中的所有联系人)
        cout << '******* 6.清空通讯录 *******' << endl;
        // 0. 退出通讯录(退出通讯录界面)
        cout << '******* 0.退出通讯录 *******' << endl;
        int choice;
        cin >> choice;
        switch (choice) {
            case 0:
                cout << '已退出通讯录系统' << endl;
                return 0;
            case 1:
                // 增加联系人
                addContact(contact);
                break;
            case 2:
                showContact(contact);
                break;
            case 3:
                deleteContact(contact);
                break;
            case 4:
                searchContact(contact);
                break;
            case 5:
                modifyContact(contact);
                break;
            case 6:
                clearContact(contact);
                break;
            default:
                cout << '选项不在功能内! 请重新选择' << endl;
                break;
        }
    }
```



#### 增删查改

对通讯录的管理可概括为增删查改功能，可采用以下两种数据结构实现

- 数组：
  - 优点：查找效率高
  - 缺点：删除效率低（后续元素都受到影响），容量固定
- 链表：
  - 优点：删除效率高（改变指针链接即可），容量不限，更灵活
  - 缺点：查找效率低



##### 数组实现的代码（完整版）：

```c++
#include <iostream>
using namespace std;

enum Sex{
    MALE,
    FEMALE
};

struct Person {
    string name;
    Sex sex; // male or female
    int age;
    string phoneNumber;
    string address;

    Person() : name(''), sex(FEMALE), age(0), phoneNumber(''), address('') {};
    Person(string n, Sex s, int a, string pN, string addr) : name(n), sex(s), age(a), phoneNumber(pN), address(addr) {};
};

// 数组存储
struct Contact
{
    struct Person person[1000];
    int cnt; // 存储通讯录中当前联系人数量

    Contact() : cnt(0) {};
};


int addContact(Contact& contact) {
    if (contact.cnt >= 1000) {
        cout << '通讯录已满，无法继续存储' << endl;
        return 0;
    }
    string name;
    cout << '请输入新增联系人姓名' << endl;
    cin >> name;
    int sex;
    cout << '请输入新增联系人性别(0表示男性, 1表示女性)' << endl;
    cin >> sex;
    while (sex != 0 && sex != 1) {
        cout << '输入不符合要求，请重新输入！' << endl;
        cin >> sex;
    }
    int age;
    cout << '请输入新增联系人年龄' << endl;
    cin >> age;
    string phoneNumber;
    cout << '请输入新增联系人联系电话' << endl;
    cin >> phoneNumber;
    string address;
    cout << '请输入新增联系人家庭住址' << endl;
    cin >> address;
    Person person(name, static_cast<Sex>(sex), age, phoneNumber, address);
    contact.person[contact.cnt] = person;
    contact.cnt++;
    return 1;
}

int showContact(Contact& contact) {
    cout << '通讯录列表如下:' << endl;
    for (int i = 0; i < contact.cnt; i++) {
        cout << '********************************' << endl;
        cout << '第' << i + 1 << '个联系人:' << endl;
        cout << '姓名' << contact.person[i].name << endl;
        cout << '性别' << contact.person[i].sex << endl;
        cout << '年龄' << contact.person[i].age << endl;
        cout << '联系电话' << contact.person[i].phoneNumber << endl;
        cout << '家庭住址' << contact.person[i].address << endl;
    }
    return 1;
}

int deleteContact(Contact& contact) {
    cout << '请输入你想删除的联系人姓名: ' << endl;
    string name;
    cin >> name;
    for (int i = 0; i < contact.cnt; i++) {
        if (contact.person[i].name == name) {
            for (int j = i + 1; j < contact.cnt; j++) {
                contact.person[j-1] = contact.person[j];
            }
            contact.cnt--;
            return 1;
        }
    }
    cout << '未查找到该联系人' << endl;
    return 0;
}

int searchContact(Contact &contact) {
    cout << '请输入你想查找的联系人姓名: ' << endl;
    string name;
    cin >> name;
    for (const Person& person : contact.person) {
        if (person.name == name) {
            cout << '姓名' << person.name << endl;
            cout << '性别' << person.sex << endl;
            cout << '年龄' << person.age << endl;
            cout << '联系电话' << person.phoneNumber << endl;
            cout << '家庭住址' << person.address << endl;
            return 1;
        }
    }
    cout << '未查找到该联系人' << endl;
    return 0;
}

int modifyContact(Contact& contact) {
    cout << '请输入你想修改的联系人姓名: ' << endl;
    string name;
    cin >> name;
    for (Person & person : contact.person) {
        if (person.name == name) {
            int sex, age;
            string phoneNumber, address;
            cout << '请输入修改后的联系人性别(0表示男性, 1表示女性)' << endl;
            cin >> sex;
            while (sex != 0 && sex != 1) {
                cout << '输入不符合要求，请重新输入！' << endl;
                cin >> sex;
            }
            cout << '请输入修改后的联系人年龄' << endl;
            cin >> age;
            cout << '请输入修改后的联系人联系电话' << endl;
            cin >> phoneNumber;
            cout << '请输入修改后的联系人家庭住址' << endl;
            cin >> address;
            person.sex = static_cast<Sex>(sex);
            person.age = age;
            person.phoneNumber = phoneNumber;
            person.address = address;
            cout << '修改成功' << endl;
            return 1;
        }
    }
    cout << '未查找到该联系人' << endl;
    return 0;
}

int clearContact(Contact& contact) {
    contact.cnt = 0;
    cout << '通讯录已清空' << endl;
    return 1;
}

int main()
{
    cout << '****欢迎来到通讯录管理系统****' << endl;
    Contact contact;
    contact.cnt = 0;
    while (true) {
        cout << '********请选择功能: ********' << endl;
        // 1. 创建通讯录(包括姓名,性别,年龄,联系电话,家庭住址)
        cout << '******* 1.创建联系人 *******' << endl;
        // 2. 显示通讯录(显示通讯录成员的基本信息)
        cout << '******* 2.显示通讯录 *******' << endl;
        // 3. 删除通讯录(删除通讯录中想删除的联系人)
        cout << '******* 3.删除联系人 *******' << endl;
        // 4. 查找通讯录(按照联系人的名字查找到具体的联系人)
        cout << '******* 4.查找联系人 *******' << endl;
        // 5. 修改通讯录(修改通讯录中联系人的基本信息)
        cout << '******* 5.修改联系人 *******' << endl;
        // 6. 清空通讯录(删除通讯录中的所有联系人)
        cout << '******* 6.清空通讯录 *******' << endl;
        // 0. 退出通讯录(退出通讯录界面)
        cout << '******* 0.退出通讯录 *******' << endl;
        int choice;
        cin >> choice;
        switch (choice) {
            case 0:
                cout << '已退出通讯录系统' << endl;
                return 0;
            case 1:
                // 增加联系人
                addContact(contact);
                break;
            case 2:
                showContact(contact);
                break;
            case 3:
                deleteContact(contact);
                break;
            case 4:
                searchContact(contact);
                break;
            case 5:
                modifyContact(contact);
                break;
            case 6:
                clearContact(contact);
                break;
            default:
                cout << '选项不在功能内! 请重新选择' << endl;
                break;
        }
    }
}

```



##### 链表实现的代码（完整版）：

```c++
#include <iostream>
using namespace std;

enum Sex{
    MALE,
    FEMALE
};

struct Person {
    string name;
    Sex sex; // male or female
    int age;
    string phoneNumber;
    string address;

    Person() : name(''), sex(FEMALE), age(0), phoneNumber(''), address('') {};
    Person(string n, Sex s, int a, string pN, string addr) : name(n), sex(s), age(a), phoneNumber(pN), address(addr) {};
};

// 链表存储
struct Contact
{
    Person person;
    Contact* next;

    Contact() : person(), next(nullptr) {};
};


int addContact(Contact& contact) {
    string name;
    cout << '请输入新增联系人姓名' << endl;
    cin >> name;
    int sex;
    cout << '请输入新增联系人性别(0表示男性, 1表示女性)' << endl;
    cin >> sex;
    while (sex != 0 && sex != 1) {
        cout << '输入不符合要求，请重新输入！' << endl;
        cin >> sex;
    }
    int age;
    cout << '请输入新增联系人年龄' << endl;
    cin >> age;
    string phoneNumber;
    cout << '请输入新增联系人联系电话' << endl;
    cin >> phoneNumber;
    string address;
    cout << '请输入新增联系人家庭住址' << endl;
    cin >> address;
    Person person(name, static_cast<Sex>(sex), age, phoneNumber, address);
    Contact* newContact = new Contact;
    newContact->person = person;
    newContact->next = nullptr;
    Contact* p = &contact;
    while (p->next != nullptr) {
        p = p->next;
    }
    p->next = newContact;
    return 1;
}

int showContact(Contact& contact) {
    cout << '通讯录列表如下:' << endl;
    Contact* p = &contact;
    p = p->next;
    int i = 0;
    while(p!= nullptr) {
        cout << '********************************' << endl;
        cout << '第' << i + 1 << '个联系人:' << endl;
        cout << '姓名' << p->person.name << endl;
        cout << '性别' << p->person.sex << endl;
        cout << '年龄' << p->person.age << endl;
        cout << '联系电话' << p->person.phoneNumber << endl;
        cout << '家庭住址' << p->person.address << endl;
        p = p->next;
        i++;
    }
    return 1;
}

int deleteContact(Contact& contact) {
    cout << '请输入你想删除的联系人姓名: ' << endl;
    string name;
    cin >> name;
    Contact* p = &contact;
    while (p->next != nullptr) {
        if (p->next->person.name == name) {
            Contact* temp = p->next;
            p->next = temp->next;
            delete temp;
            cout << '删除成功' << endl;
            return 1;
        }
        p = p->next;
    }
    cout << '未查找到该联系人' << endl;
    return 0;
}

int searchContact(Contact &contact) {
    cout << '请输入你想查找的联系人姓名: ' << endl;
    string name;
    cin >> name;
    Contact* p = &contact;
    p = p->next;
    while (p != nullptr) {
        if (p->person.name == name) {
            cout << '姓名' << p->person.name << endl;
            cout << '性别' << p->person.sex << endl;
            cout << '年龄' << p->person.age << endl;
            cout << '联系电话' << p->person.phoneNumber << endl;
            cout << '家庭住址' << p->person.address << endl;
            return 1;
        }
        p = p->next;
    }
    cout << '未查找到该联系人' << endl;
    return 0;
}

int modifyContact(Contact& contact) {
    cout << '请输入你想修改的联系人姓名: ' << endl;
    string name;
    cin >> name;
    Contact* p = &contact;
    p = p->next;
    while (p != nullptr) {
        if (p->person.name == name) {
            int sex, age;
            string phoneNumber, address;
            cout << '请输入修改后的联系人性别(0表示男性, 1表示女性)' << endl;
            cin >> sex;
            while (sex != 0 && sex != 1) {
                cout << '输入不符合要求，请重新输入！' << endl;
                cin >> sex;
            }
            cout << '请输入修改后的联系人年龄' << endl;
            cin >> age;
            cout << '请输入修改后的联系人联系电话' << endl;
            cin >> phoneNumber;
            cout << '请输入修改后的联系人家庭住址' << endl;
            cin >> address;
            p->person.sex = static_cast<Sex>(sex);
            p->person.age = age;
            p->person.phoneNumber = phoneNumber;
            p->person.address = address;
            cout << '修改成功' << endl;
            return 1;
        }
        p = p->next;
    }
    cout << '未查找到该联系人' << endl;
    return 0;
}

int clearContact(Contact& contact) {
    contact.next = nullptr;
    cout << '通讯录已清空' << endl;
    return 1;
}

int main()
{
    cout << '****欢迎来到通讯录管理系统****' << endl;
    Contact contact;
    while (true) {
        cout << '********请选择功能: ********' << endl;
        // 1. 创建通讯录(包括姓名,性别,年龄,联系电话,家庭住址)
        cout << '******* 1.创建联系人 *******' << endl;
        // 2. 显示通讯录(显示通讯录成员的基本信息)
        cout << '******* 2.显示通讯录 *******' << endl;
        // 3. 删除通讯录(删除通讯录中想删除的联系人)
        cout << '******* 3.删除联系人 *******' << endl;
        // 4. 查找通讯录(按照联系人的名字查找到具体的联系人)
        cout << '******* 4.查找联系人 *******' << endl;
        // 5. 修改通讯录(修改通讯录中联系人的基本信息)
        cout << '******* 5.修改联系人 *******' << endl;
        // 6. 清空通讯录(删除通讯录中的所有联系人)
        cout << '******* 6.清空通讯录 *******' << endl;
        // 0. 退出通讯录(退出通讯录界面)
        cout << '******* 0.退出通讯录 *******' << endl;
        int choice;
        cin >> choice;
        switch (choice) {
            case 0:
                cout << '已退出通讯录系统' << endl;
                return 0;
            case 1:
                // 增加联系人
                addContact(contact);
                break;
            case 2:
                showContact(contact);
                break;
            case 3:
                deleteContact(contact);
                break;
            case 4:
                searchContact(contact);
                break;
            case 5:
                modifyContact(contact);
                break;
            case 6:
                clearContact(contact);
                break;
            default:
                cout << '选项不在功能内! 请重新选择' << endl;
                break;
        }
    }
}
```。

用C++实现一个简易计算器，实现小数的加减乘除计算的基本功能
#### 考察知识点：
- 输入输出
- 栈
- 异常处理
- 类型转换
- 函数传参

#### 功能实现：
- 中缀表达式转后缀表达式
- 后缀表达式计算

#### 中缀表达式转后缀表达式
首先获取输入的中缀表达式字符串，实现以下到后缀表达式的转换，如：
`3 + 5 * 10 ——> 3 5 10 * +`
那么这里需要准备一个栈，控制操作符的进出顺序，操作数的顺序没有改变，直接保留即可
流程：
1. 定义一个指针，遍历中缀表达式字符串，遇到操作数，直接添加到结果
2. 遇到操作符，则判断情况，优先级大的操作符直接进栈
    1. 操作符为'(' or '*' or '\'：直接进栈（`stack.push(op)`）
    2. 操作符为'+' or '-': 一直出栈（`stack.pop()`），加入结果中的后缀表达式，直到栈顶（`stack.top()`）元素的操作符优先级不高于当前op
    3. 操作符为')'：一直出栈，，加入结果中的后缀表达式，直到栈顶元素为'('，出栈，不加入结果
3. 遍历结束，弹出所有栈中元素（循环终止条件`stack.empty()`）

#### 后缀表达式的计算
维护一个操作数栈，
流程：
1. 定义一个指针，从左至右依次读取后缀表达式的元素，遇到操作数就进栈
2. 遇到操作符就计算（`switch-case`加减乘除四种情况），将栈顶两元素的值计算后重新压栈


#### 异常处理
**除0异常**:自定义异常`throw std::invalid_argument('Division by zero')`，需包含`<stdexcept>`头文件

#### 类型转换
- `char`转`int`: `int(ch-'0')`即可
- `int`转`double`: 直接强制类型转换

#### 函数传参
- 传值: 函数内部对参数的修改不会影响外部
- 传址: 函数参数中携带&标识，标识传值，函数对该参数的修改是全局的

#### 代码如下
```
#include<iostream>
#include <stack>
#include <cmath>
#include <iomanip>
#include <sstream>
using namespace std;

std::string double_to_string(double value) {
    // 使用ostringstream创建字符串流
    ostringstream out;
    // 设置fixed格式以避免科学计数法
    out << fixed << setprecision(10) << value; // 设置足够多的小数位，之后再处理
    std::string result = out.str();
    // 查找最后一个小数点的位置
    size_t pos = result.find('.');
    if (pos != string::npos) {
        // 去除小数点后无效的0
        result.erase(result.find_last_not_of('0') + 1, string::npos);
        // 如果小数点是最后一个字符，去掉小数点
        if (result.back() == '.') {
            result.pop_back();
        }
    }
    return result;
}

double getnum(string& input, int& i) {
    int num = int(input[i] - '0');
    i++;
    while (i < input.length() && isdigit(input[i])) {
        num = num * 10 + int(input[i] - '0');
        i++;
    }
    double xiaoshu = 0;
    int index = 1;
    if (input[i] == '.') {
        i++;
        while (i < input.length() && isdigit(input[i])) {
            xiaoshu += (input[i] - '0') * pow(0.1, index);
            i++;
        }
    }
    double operand = num + xiaoshu;
    return operand;
}

// 中缀表达式转后缀表达式
string infix_to_postfix(string& input) {
    string output = '';
    stack<char> operators;
    // 3 + 5 * 10 ——> 3 5 10 * +
    for (int i = 0; i < input.length(); i++) {
        char c = input[i];
        if (isdigit(c)) {
            double operand = getnum(input, i);
            output += double_to_string(operand) + ' ';
            c = input[i];
        }
        if (c == '(' || c == '*' || c == '/') {
            operators.push(c);
        } else if (c == ')') {
            while (!operators.empty() && operators.top() != '(') {
                output += string(1, operators.top()) + ' ';
                operators.pop();
            }
            if (!operators.empty() && operators.top() == '(') {
                operators.pop();
            }
        } else if (c == '+' || c == '-') {
            while (!operators.empty() && operators.top() != '(' && (operators.top() == '*' || operators.top() == '/')) {
                output += string(1, operators.top()) + ' ';
                operators.pop();
            }
            operators.push(c);
        }
    }
    while (!operators.empty()) {
        output += string(1, operators.top()) + ' ';
        operators.pop();
    }
    return output;
}

double calc(string& postfix_expression) {
    stack<double> operands;
    for (int i = 0; i < postfix_expression.length(); i++) {
        char c = postfix_expression[i];
        if (isdigit(c)) {
            double operand = getnum(postfix_expression, i);
            operands.push(operand);
            c = postfix_expression[i];
        }
        double op1, op2;
        if (c == '+' || c == '-' || c == '*' || c == '/') {
            op1 = operands.top();
            operands.pop();
            op2 = operands.top();
            operands.pop();
        } else {
            continue;
        }
        switch (c) {
            case '+':
                operands.push(op1 + op2);
                break;
            case '-':
                operands.push(op1 - op2);
                break;
            case '*':
                operands.push(op1 * op2);
                break;
            case '/': {
                if (op2 == 0) {
                    cout << 'Error: division by zero' << endl;
                    return 0;
                }
                operands.push(op1 / op2);
                break;
            }
        }
    }
    return operands.top();
}

// 实现一个计算器
int main() {
    string input;
    while (true) {
        cout << 'Enter an expression: ' << endl;
        getline(cin, input);
        if (input == 'exit') {
            break;
        }
        string new_expression = infix_to_postfix(input);
        // 打印一下中间结果：后缀表达式
        cout << 'Postfix expression: ' << new_expression << endl;
        // 根据后缀表达式计算结果
        double result = calc(new_expression);
        cout << 'Result: ' << result << endl;
    }
}
